import Vue from "vue";
import VueRouter from "vue-router";
import layout from "@/views/layout.vue"
import home from "@/views/home.vue"

Vue.use(VueRouter)

const routes = [
    {
        path: '/',
        redirect: '/layout'
    },
    {
        path: '/layout',
        component: layout,
        redirect: '/layout/home',
        children: [
            {
                path: 'home',
                component: home
            },
        ]
    },
    {
        path: "*",
        redirect: "/layout"
    }
]

const router = new VueRouter({
    routes
})

export default router